// n8n Function node
// Goal: flatten Slack messages → keep only: ts (Slack) + msg string
// Requirements: include ALL block text (sections, headers, context, rich_text); no user IDs; no thread_ts
// Sort output by ts (ascending); include ISO timestamp; keep your exact output shape

function extractTextFromBlocks(blocks = []) {
  const parts = [];

  for (const b of blocks) {
    // 1) section: mrkdwn text
    if (b.type === 'section') {
      if (b.text?.type === 'mrkdwn' && typeof b.text.text === 'string') {
        parts.push(b.text.text);
      }
      // section: fields (array of mrkdwn/plain_text)
      if (Array.isArray(b.fields) && b.fields.length) {
        const fieldTexts = b.fields
          .map(f => (typeof f.text === 'string' ? f.text : ''))
          .filter(Boolean);
        if (fieldTexts.length) parts.push(fieldTexts.join('\n'));
      }
    }

    // 2) header: plain_text
    else if (b.type === 'header' && b.text?.type === 'plain_text' && typeof b.text.text === 'string') {
      parts.push(`*${b.text.text}*`);
    }

    // 3) context: elements (mrkdwn/plain_text)
    else if (b.type === 'context' && Array.isArray(b.elements)) {
      const ctx = b.elements
        .map(el => (typeof el.text === 'string' ? el.text : ''))
        .filter(Boolean);
      if (ctx.length) parts.push(ctx.join(' '));
    }

    // 4) rich_text: nested text segments
    else if (b.type === 'rich_text' && Array.isArray(b.elements)) {
      for (const el of b.elements) {
        if (el.type === 'rich_text_section' && Array.isArray(el.elements)) {
          const segs = el.elements
            .filter(s => s.type === 'text' && typeof s.text === 'string')
            .map(s => s.text);
          if (segs.length) parts.push(segs.join(''));
        }
      }
    }

    // 5) image (optional): include alt text if present
    else if (b.type === 'image' && typeof b.alt_text === 'string' && b.alt_text.trim()) {
      parts.push(`_(image: ${b.alt_text.trim()})_`);
    }

    // actions/divider/etc. have no human text → ignore
  }

  return parts.join('\n\n').trim();
}

function bestUserName(msg) {
  if (msg.bot_profile?.name) return msg.bot_profile.name; // bots
  if (msg.username) return msg.username; // webhook-style
  if (msg.user_profile?.display_name) return msg.user_profile.display_name;
  if (msg.user_profile?.real_name) return msg.user_profile.real_name;
  return 'Unknown';
}

function toIsoFromSlackTs(ts) {
  const [secStr, fracStr = '0'] = String(ts || '0').split('.');
  const sec = Number(secStr || 0);
  // Slack fractional part is microseconds; convert to ms
  const ms = Math.floor(Number(fracStr.padEnd(6, '0').slice(0, 3)));
  return new Date(sec * 1000 + ms).toISOString();
}

function normalizeReactions(reactions = []) {
  return reactions.map(r => ({
    name: r.name,
    count: Number(r.count || 0)
  }));
}

const out = [];

for (const item of $input.all()) {
  const body = item.json || {};
  const messages = Array.isArray(body.messages) ? body.messages : [];

  for (const m of messages) {
    const baseText = (typeof m.text === 'string' ? m.text : '').trim();
    const blocksText = Array.isArray(m.blocks) ? extractTextFromBlocks(m.blocks) : '';
    const reactions = m.reactions ? normalizeReactions(m.reactions) : [];
    const iso = toIsoFromSlackTs(m.ts);

    // Always include blocks after base text (if both exist)
    const textParts = [];
    if (baseText) textParts.push(baseText);
    if (blocksText) textParts.push(blocksText);
    const fullText = textParts.join('\n\n'); // separator between base text and blocks

    out.push({
      ts: Number(m.ts),
      msg:
        `FROM: ${bestUserName(m)} at ${iso}\n` +
        `${fullText || ''}` +
        (reactions.length ? `\nREACTIONS: ${JSON.stringify(reactions)}` : '')
    });
  }
}

// Sort by ts ascending
out.sort((a, b) => a.ts - b.ts);

return {
  messages: out,
  output: out.map(o => o.msg).join('\n')
};
